module RefModule(
    input [15:0] in0,
    input [15:0] in1,
    output reg [31:0] out
);reg [31:0] final_sig;
integer i, j;

always @(*) begin
    final_sig = 0;
    for (i = 0; i < 16; i = i + 1) begin
        if (in0[i] == 1) begin
            for (j = 0; j < 16; j = j + 1) begin
                if (in1[j] == 1) begin
                    final_sig = final_sig + (1 << (i + j));
                end
            end
        end
    end
    out = final_sig;
end

endmodule
